# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit
import UserNotifications
import Social

class AppURLProtocol: NSObject, UISceneDelegate {
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        if let url = URLContexts.first?.url {
            guard let token = url.queryItems?.first(where: { $0.name == "token" })?.value else { return }
            let storyboard = UIStoryboard(name: "Main", bundle: Bundle.main)
            if let passwordResetVC = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController") as? PasswordResetViewController {
                passwordResetVC.token = token
                scene.window?.rootViewController = UINavigationController(rootViewController: passwordResetVC)
            }
        }
    }
}

@main
struct AppDelegate: UIResponder, UIApplicationDelegate {
    var window: UIWindow?

    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        let scene = (UIApplication.shared.connectedScenes.first as? UIScene)?.delegate as? SceneDelegate
        guard let windowScene = (scene as? AppURLProtocol.Type)?.window else { return false }
        self.window = windowScene
        window?.rootViewController = UIStoryboard(name: "Main", bundle: Bundle.main).instantiateInitialViewController()
        return true
    }
}